package com.securebank.app.model;

import java.io.Serializable;

public class TransactionResult implements Serializable {
    private boolean success;
    private String transactionId;
    private String message;
    private String errorCode;
    private Transaction.TransactionStatus status;

    public TransactionResult() {}

    public static TransactionResult success(String transactionId, String message) {
        TransactionResult result = new TransactionResult();
        result.success = true;
        result.transactionId = transactionId;
        result.message = message;
        result.status = Transaction.TransactionStatus.COMPLETED;
        return result;
    }

    public static TransactionResult failure(String errorCode, String message) {
        TransactionResult result = new TransactionResult();
        result.success = false;
        result.errorCode = errorCode;
        result.message = message;
        result.status = Transaction.TransactionStatus.FAILED;
        return result;
    }

    public boolean isSuccess() { return success; }
    public String getTransactionId() { return transactionId; }
    public String getMessage() { return message; }
    public String getErrorCode() { return errorCode; }
    public Transaction.TransactionStatus getStatus() { return status; }
}

