package com.securebank.app.security;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public class InputValidator {

    private static final Pattern ACCOUNT_NUMBER_PATTERN =
            Pattern.compile("^[0-9]{8,20}$");
    private static final Pattern AMOUNT_PATTERN =
            Pattern.compile("^[0-9]+(\\.[0-9]{1,2})?$");
    private static final Pattern DESCRIPTION_PATTERN =
            Pattern.compile("^[a-zA-Z0-9\\s\\-_.,'\"!?()]{0,200}$");
    private static final Pattern BENEFICIARY_NAME_PATTERN =
            Pattern.compile("^[a-zA-Z\\s\\-'.]{1,100}$");

    private static final BigDecimal MIN_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal MAX_SINGLE_TRANSACTION = new BigDecimal("50000.00");
    private static final BigDecimal MAX_DAILY_LIMIT = new BigDecimal("100000.00");

    public static ValidationResult validateAccountNumber(String accountNumber) {
        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            return ValidationResult.error("Account number is required");
        }
        String cleaned = accountNumber.trim();
        if (!ACCOUNT_NUMBER_PATTERN.matcher(cleaned).matches()) {
            return ValidationResult.error("Invalid account number format");
        }
        return ValidationResult.success(cleaned);
    }

    public static ValidationResult validateAmount(String amountStr) {
        if (amountStr == null || amountStr.trim().isEmpty()) {
            return ValidationResult.error("Amount is required");
        }
        String cleaned = amountStr.trim();
        if (!AMOUNT_PATTERN.matcher(cleaned).matches()) {
            return ValidationResult.error("Invalid amount format");
        }
        try {
            BigDecimal amount = new BigDecimal(cleaned);
            if (amount.compareTo(MIN_AMOUNT) < 0) {
                return ValidationResult.error(
                        "Minimum transaction amount is " + MIN_AMOUNT);
            }
            if (amount.compareTo(MAX_SINGLE_TRANSACTION) > 0) {
                return ValidationResult.error(
                        "Maximum single transaction amount is " + MAX_SINGLE_TRANSACTION);
            }
            return ValidationResult.success(cleaned);
        } catch (NumberFormatException e) {
            return ValidationResult.error("Invalid amount");
        }
    }

    public static ValidationResult validateDescription(String description) {
        if (description == null || description.trim().isEmpty()) {
            return ValidationResult.success("");
        }
        String cleaned = description.trim();
        if (!DESCRIPTION_PATTERN.matcher(cleaned).matches()) {
            return ValidationResult.error(
                    "Description contains invalid characters");
        }
        return ValidationResult.success(sanitizeInput(cleaned));
    }

    public static ValidationResult validateBeneficiaryName(String name) {
        if (name == null || name.trim().isEmpty()) {
            return ValidationResult.error("Beneficiary name is required");
        }
        String cleaned = name.trim();
        if (!BENEFICIARY_NAME_PATTERN.matcher(cleaned).matches()) {
            return ValidationResult.error("Invalid beneficiary name");
        }
        return ValidationResult.success(sanitizeInput(cleaned));
    }

    public static String sanitizeInput(String input) {
        if (input == null) return "";
        return input
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;")
                .replace("&", "&amp;")
                .replace("/", "&#x2F;");
    }

    public static boolean isWithinDailyLimit(BigDecimal currentDailyTotal,
                                              BigDecimal newAmount) {
        return currentDailyTotal.add(newAmount).compareTo(MAX_DAILY_LIMIT) <= 0;
    }

    public static class ValidationResult {
        private final boolean valid;
        private final String sanitizedValue;
        private final String errorMessage;

        private ValidationResult(boolean valid, String sanitizedValue,
                                 String errorMessage) {
            this.valid = valid;
            this.sanitizedValue = sanitizedValue;
            this.errorMessage = errorMessage;
        }

        public static ValidationResult success(String sanitizedValue) {
            return new ValidationResult(true, sanitizedValue, null);
        }

        public static ValidationResult error(String errorMessage) {
            return new ValidationResult(false, null, errorMessage);
        }

        public boolean isValid() { return valid; }
        public String getSanitizedValue() { return sanitizedValue; }
        public String getErrorMessage() { return errorMessage; }
    }
}

