package com.securebank.app.network;

import android.content.Context;
import android.util.Log;

import com.securebank.app.security.SecureStorageManager;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.CertificatePinner;
import okhttp3.Interceptor;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;

public class SecureApiClient {

    private static final String TAG = "SecureApiClient";
    private static final String BASE_URL = "https://api.securebank.com/v1";
    private static final int CONNECT_TIMEOUT = 30;
    private static final int READ_TIMEOUT = 30;
    private static final int WRITE_TIMEOUT = 30;

    private static volatile SecureApiClient instance;
    private final OkHttpClient httpClient;
    private final SecureStorageManager storageManager;

    private SecureApiClient(Context context) {
        storageManager = SecureStorageManager.getInstance(context);

        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add("api.securebank.com",
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                .add("api.securebank.com",
                        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
                .build();

        httpClient = new OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
                .certificatePinner(certificatePinner)
                .addInterceptor(new AuthInterceptor())
                .addInterceptor(new SecurityHeadersInterceptor())
                .build();
    }

    public static SecureApiClient getInstance(Context context) {
        if (instance == null) {
            synchronized (SecureApiClient.class) {
                if (instance == null) {
                    instance = new SecureApiClient(context.getApplicationContext());
                }
            }
        }
        return instance;
    }

    public OkHttpClient getClient() {
        return httpClient;
    }

    public String getBaseUrl() {
        return BASE_URL;
    }

    private class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();

            String token = storageManager.getAuthToken();
            if (token == null) {
                return chain.proceed(original);
            }

            Request.Builder requestBuilder = original.newBuilder()
                    .header("Authorization", "Bearer " + token)
                    .method(original.method(), original.body());

            return chain.proceed(requestBuilder.build());
        }
    }

    private static class SecurityHeadersInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();

            Request request = original.newBuilder()
                    .header("Content-Type", "application/json")
                    .header("Accept", "application/json")
                    .header("X-Requested-With", "SecureBankApp")
                    .header("Cache-Control", "no-cache, no-store, must-revalidate")
                    .header("Pragma", "no-cache")
                    .build();

            Response response = chain.proceed(request);

            // Verify response is from expected server
            String serverHeader = response.header("X-Server-Signature");
            if (serverHeader == null && response.isSuccessful()) {
                Log.w("SecurityHeaders",
                        "Response missing server signature header");
            }

            return response;
        }
    }
}

