package com.securebank.app.network;

import android.content.Context;
import android.util.Log;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import com.securebank.app.model.Account;
import com.securebank.app.model.Transaction;
import com.securebank.app.model.TransactionResult;

import java.io.IOException;
import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

public class TransactionApiService {

    private static final String TAG = "TransactionApiService";
    private static final MediaType JSON =
            MediaType.parse("application/json; charset=utf-8");

    private final SecureApiClient apiClient;
    private final Gson gson;
    private final ExecutorService executorService;

    public TransactionApiService(Context context) {
        this.apiClient = SecureApiClient.getInstance(context);
        this.gson = new GsonBuilder()
                .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
                .create();
        this.executorService = Executors.newFixedThreadPool(3);
    }

    public CompletableFuture<List<Account>> fetchAccounts() {
        return CompletableFuture.supplyAsync(() -> {
            OkHttpClient client = apiClient.getClient();
            String url = apiClient.getBaseUrl() + "/accounts";

            Request request = new Request.Builder()
                    .url(url)
                    .get()
                    .build();

            try (Response response = client.newCall(request).execute()) {
                if (!response.isSuccessful()) {
                    throw new IOException("Failed to fetch accounts: " +
                            response.code());
                }
                String body = response.body().string();
                Account[] accounts = gson.fromJson(body, Account[].class);
                List<Account> accountList = new ArrayList<>();
                if (accounts != null) {
                    for (Account account : accounts) {
                        accountList.add(account);
                    }
                }
                return accountList;
            } catch (IOException e) {
                Log.e(TAG, "Error fetching accounts", e);
                throw new RuntimeException("Failed to fetch accounts", e);
            }
        }, executorService);
    }

    public CompletableFuture<Account> fetchAccountBalance(String accountId) {
        return CompletableFuture.supplyAsync(() -> {
            OkHttpClient client = apiClient.getClient();
            String url = apiClient.getBaseUrl() + "/accounts/" + accountId + "/balance";

            Request request = new Request.Builder()
                    .url(url)
                    .get()
                    .build();

            try (Response response = client.newCall(request).execute()) {
                if (!response.isSuccessful()) {
                    throw new IOException("Failed to fetch balance: " +
                            response.code());
                }
                String body = response.body().string();
                return gson.fromJson(body, Account.class);
            } catch (IOException e) {
                Log.e(TAG, "Error fetching balance", e);
                throw new RuntimeException("Failed to fetch balance", e);
            }
        }, executorService);
    }

    public CompletableFuture<TransactionResult> submitTransaction(
            Transaction transaction) {
        return CompletableFuture.supplyAsync(() -> {
            OkHttpClient client = apiClient.getClient();
            String url = apiClient.getBaseUrl() + "/transactions";

            String jsonBody = gson.toJson(transaction);
            RequestBody requestBody = RequestBody.create(jsonBody, JSON);

            Request request = new Request.Builder()
                    .url(url)
                    .post(requestBody)
                    .header("Idempotency-Key", transaction.getIdempotencyKey())
                    .build();

            try (Response response = client.newCall(request).execute()) {
                String body = response.body().string();

                if (response.isSuccessful()) {
                    return gson.fromJson(body, TransactionResult.class);
                } else if (response.code() == 409) {
                    // Duplicate transaction (idempotency)
                    return TransactionResult.failure("DUPLICATE",
                            "This transaction has already been processed");
                } else if (response.code() == 422) {
                    return TransactionResult.failure("VALIDATION_ERROR",
                            "Transaction validation failed");
                } else if (response.code() == 403) {
                    return TransactionResult.failure("INSUFFICIENT_FUNDS",
                            "Insufficient funds for this transaction");
                } else {
                    return TransactionResult.failure("SERVER_ERROR",
                            "Transaction failed. Please try again later.");
                }
            } catch (IOException e) {
                Log.e(TAG, "Error submitting transaction", e);
                return TransactionResult.failure("NETWORK_ERROR",
                        "Network error. Please check your connection.");
            }
        }, executorService);
    }

    public CompletableFuture<List<Transaction>> fetchTransactionHistory(
            String accountId, int page, int pageSize) {
        return CompletableFuture.supplyAsync(() -> {
            OkHttpClient client = apiClient.getClient();
            String url = String.format("%s/accounts/%s/transactions?page=%d&size=%d",
                    apiClient.getBaseUrl(), accountId, page, pageSize);

            Request request = new Request.Builder()
                    .url(url)
                    .get()
                    .build();

            try (Response response = client.newCall(request).execute()) {
                if (!response.isSuccessful()) {
                    throw new IOException("Failed to fetch transaction history: " +
                            response.code());
                }
                String body = response.body().string();
                Transaction[] transactions = gson.fromJson(body,
                        Transaction[].class);
                List<Transaction> transactionList = new ArrayList<>();
                if (transactions != null) {
                    for (Transaction txn : transactions) {
                        transactionList.add(txn);
                    }
                }
                return transactionList;
            } catch (IOException e) {
                Log.e(TAG, "Error fetching transaction history", e);
                throw new RuntimeException(
                        "Failed to fetch transaction history", e);
            }
        }, executorService);
    }

    public void shutdown() {
        executorService.shutdown();
    }
}

