package com.securebank.app.service;

import android.content.Context;
import android.util.Log;

import com.securebank.app.model.Account;
import com.securebank.app.model.Transaction;
import com.securebank.app.model.TransactionResult;
import com.securebank.app.network.TransactionApiService;
import com.securebank.app.security.InputValidator;

import java.math.BigDecimal;
import java.util.concurrent.CompletableFuture;

public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";

    public interface TransactionCallback {
        void onValidationError(String field, String error);
        void onTransactionStarted(String transactionId);
        void onTransactionComplete(TransactionResult result);
        void onTransactionError(String error);
    }

    private final TransactionApiService apiService;
    private final AuditLogger auditLogger;

    public TransactionProcessor(Context context) {
        this.apiService = new TransactionApiService(context);
        this.auditLogger = new AuditLogger(context);
    }

    public void processTransfer(String fromAccountId, String toAccountNumber,
                                 String beneficiaryName, String amountStr,
                                 String description, TransactionCallback callback) {

        // Step 1: Validate all inputs
        InputValidator.ValidationResult accountResult =
                InputValidator.validateAccountNumber(toAccountNumber);
        if (!accountResult.isValid()) {
            callback.onValidationError("accountNumber",
                    accountResult.getErrorMessage());
            return;
        }

        InputValidator.ValidationResult amountResult =
                InputValidator.validateAmount(amountStr);
        if (!amountResult.isValid()) {
            callback.onValidationError("amount",
                    amountResult.getErrorMessage());
            return;
        }

        InputValidator.ValidationResult beneficiaryResult =
                InputValidator.validateBeneficiaryName(beneficiaryName);
        if (!beneficiaryResult.isValid()) {
            callback.onValidationError("beneficiaryName",
                    beneficiaryResult.getErrorMessage());
            return;
        }

        InputValidator.ValidationResult descriptionResult =
                InputValidator.validateDescription(description);
        if (!descriptionResult.isValid()) {
            callback.onValidationError("description",
                    descriptionResult.getErrorMessage());
            return;
        }

        // Step 2: Create transaction object with sanitized inputs
        Transaction transaction = new Transaction();
        transaction.setFromAccountId(fromAccountId);
        transaction.setToAccountNumber(accountResult.getSanitizedValue());
        transaction.setBeneficiaryName(beneficiaryResult.getSanitizedValue());
        transaction.setAmount(new BigDecimal(amountResult.getSanitizedValue()));
        transaction.setDescription(descriptionResult.getSanitizedValue());
        transaction.setType(Transaction.TransactionType.TRANSFER);
        transaction.setCurrency("USD");

        callback.onTransactionStarted(transaction.getTransactionId());

        // Step 3: Log the transaction attempt
        auditLogger.logTransactionAttempt(transaction);

        // Step 4: Submit to API
        CompletableFuture<TransactionResult> future =
                apiService.submitTransaction(transaction);

        future.thenAccept(result -> {
            if (result.isSuccess()) {
                auditLogger.logTransactionSuccess(transaction);
            } else {
                auditLogger.logTransactionFailure(transaction,
                        result.getErrorCode());
            }
            callback.onTransactionComplete(result);
        }).exceptionally(throwable -> {
            Log.e(TAG, "Transaction processing error", throwable);
            auditLogger.logTransactionError(transaction,
                    throwable.getMessage());
            callback.onTransactionError(
                    "An unexpected error occurred. Please try again.");
            return null;
        });
    }

    public CompletableFuture<Account> getAccountBalance(String accountId) {
        return apiService.fetchAccountBalance(accountId);
    }

    public void shutdown() {
        apiService.shutdown();
    }
}

