package com.securebank.app.service;

import android.content.Context;
import android.util.Log;

import com.securebank.app.model.Transaction;
import com.securebank.app.security.SecureStorageManager;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class AuditLogger {

    private static final String TAG = "AuditLogger";
    private final SecureStorageManager storageManager;

    public AuditLogger(Context context) {
        this.storageManager = SecureStorageManager.getInstance(context);
    }

    public void logTransactionAttempt(Transaction transaction) {
        String logEntry = String.format(Locale.US,
                "TRANSACTION_ATTEMPT | id=%s | type=%s | from=%s | amount=%s | time=%s | user=%s",
                transaction.getTransactionId(),
                transaction.getType(),
                maskSensitiveData(transaction.getFromAccountId()),
                transaction.getAmount(),
                getCurrentTimestamp(),
                storageManager.getUserId());
        Log.i(TAG, logEntry);
        // In production, send to secure server-side logging
    }

    public void logTransactionSuccess(Transaction transaction) {
        String logEntry = String.format(Locale.US,
                "TRANSACTION_SUCCESS | id=%s | type=%s | time=%s",
                transaction.getTransactionId(),
                transaction.getType(),
                getCurrentTimestamp());
        Log.i(TAG, logEntry);
    }

    public void logTransactionFailure(Transaction transaction, String errorCode) {
        String logEntry = String.format(Locale.US,
                "TRANSACTION_FAILED | id=%s | error=%s | time=%s",
                transaction.getTransactionId(),
                errorCode,
                getCurrentTimestamp());
        Log.w(TAG, logEntry);
    }

    public void logTransactionError(Transaction transaction, String error) {
        String logEntry = String.format(Locale.US,
                "TRANSACTION_ERROR | id=%s | error=%s | time=%s",
                transaction.getTransactionId(),
                error,
                getCurrentTimestamp());
        Log.e(TAG, logEntry);
    }

    public void logSecurityEvent(String eventType, String details) {
        String logEntry = String.format(Locale.US,
                "SECURITY_EVENT | type=%s | details=%s | time=%s | user=%s",
                eventType,
                details,
                getCurrentTimestamp(),
                storageManager.getUserId());
        Log.w(TAG, logEntry);
    }

    public void logLoginAttempt(boolean success, String method) {
        String logEntry = String.format(Locale.US,
                "LOGIN_%s | method=%s | time=%s",
                success ? "SUCCESS" : "FAILED",
                method,
                getCurrentTimestamp());
        Log.i(TAG, logEntry);
    }

    private String maskSensitiveData(String data) {
        if (data == null || data.length() <= 4) return "****";
        return "****" + data.substring(data.length() - 4);
    }

    private String getCurrentTimestamp() {
        return new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'",
                Locale.US).format(new Date());
    }
}

