package com.securebank.app.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import com.securebank.app.R;
import com.securebank.app.security.BiometricAuthManager;
import com.securebank.app.security.RootDetector;
import com.securebank.app.security.SecureStorageManager;
import com.securebank.app.service.AuditLogger;

public class LoginActivity extends AppCompatActivity {

    private EditText editUsername;
    private EditText editPassword;
    private Button btnLogin;
    private Button btnBiometric;
    private ProgressBar progressBar;
    private TextView tvError;

    private BiometricAuthManager biometricManager;
    private SecureStorageManager storageManager;
    private AuditLogger auditLogger;
    private int failedAttempts = 0;
    private static final int MAX_FAILED_ATTEMPTS = 5;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Prevent screenshots and screen recording
        getWindow().setFlags(
                WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE);

        setContentView(R.layout.activity_login);

        storageManager = SecureStorageManager.getInstance(this);
        biometricManager = new BiometricAuthManager(this);
        auditLogger = new AuditLogger(this);

        initViews();
        performSecurityChecks();
        setupListeners();
    }

    private void initViews() {
        editUsername = findViewById(R.id.edit_username);
        editPassword = findViewById(R.id.edit_password);
        btnLogin = findViewById(R.id.btn_login);
        btnBiometric = findViewById(R.id.btn_biometric);
        progressBar = findViewById(R.id.progress_bar);
        tvError = findViewById(R.id.tv_error);

        if (biometricManager.isBiometricAvailable()) {
            btnBiometric.setVisibility(View.VISIBLE);
        } else {
            btnBiometric.setVisibility(View.GONE);
        }
    }

    private void performSecurityChecks() {
        if (RootDetector.isDeviceRooted()) {
            auditLogger.logSecurityEvent("ROOT_DETECTED",
                    "App launched on rooted device");
            new AlertDialog.Builder(this)
                    .setTitle("Security Warning")
                    .setMessage("This device appears to be rooted. " +
                            "For your security, banking operations are " +
                            "restricted on modified devices.")
                    .setPositiveButton("Exit", (d, w) -> finish())
                    .setCancelable(false)
                    .show();
            return;
        }

        if (RootDetector.isEmulator()) {
            auditLogger.logSecurityEvent("EMULATOR_DETECTED",
                    "App launched on emulator");
            // Allow in debug builds, block in release
            if (!BuildConfig.DEBUG) {
                new AlertDialog.Builder(this)
                        .setTitle("Unsupported Device")
                        .setMessage("This app cannot run on emulated devices.")
                        .setPositiveButton("Exit", (d, w) -> finish())
                        .setCancelable(false)
                        .show();
            }
        }
    }

    private void setupListeners() {
        btnLogin.setOnClickListener(v -> attemptLogin());

        btnBiometric.setOnClickListener(v -> {
            biometricManager.authenticate(this,
                    "Biometric Login",
                    "Use your fingerprint to login",
                    new BiometricAuthManager.BiometricCallback() {
                        @Override
                        public void onAuthenticationSuccess() {
                            auditLogger.logLoginAttempt(true, "BIOMETRIC");
                            storageManager.refreshSession();
                            navigateToBalance();
                        }

                        @Override
                        public void onAuthenticationError(String errorMessage) {
                            auditLogger.logLoginAttempt(false,
                                    "BIOMETRIC: " + errorMessage);
                            showError("Biometric authentication failed: " +
                                    errorMessage);
                        }

                        @Override
                        public void onAuthenticationFailed() {
                            auditLogger.logLoginAttempt(false,
                                    "BIOMETRIC");
                            showError("Biometric not recognized");
                        }

                        @Override
                        public void onBiometricNotAvailable() {
                            showError("Biometric authentication not available");
                        }
                    });
        });
    }

    private void attemptLogin() {
        if (failedAttempts >= MAX_FAILED_ATTEMPTS) {
            auditLogger.logSecurityEvent("ACCOUNT_LOCKED",
                    "Too many failed login attempts");
            showError("Account temporarily locked. Please try again later.");
            btnLogin.setEnabled(false);
            return;
        }

        String username = editUsername.getText().toString().trim();
        String password = editPassword.getText().toString();

        if (username.isEmpty() || password.isEmpty()) {
            showError("Please enter username and password");
            return;
        }

        showLoading(true);

        // In production, this would call the authentication API
        // Simulating async authentication
        btnLogin.postDelayed(() -> {
            // This is a placeholder — real implementation calls server
            simulateAuthentication(username, password);
        }, 1000);
    }

    private void simulateAuthentication(String username, String password) {
        // In a real app, this calls the secure API endpoint
        // For demonstration, we simulate success/failure
        showLoading(false);

        // Placeholder: In production, validate against server
        boolean authenticated = true; // Replace with actual API call result

        if (authenticated) {
            failedAttempts = 0;
            auditLogger.logLoginAttempt(true, "PASSWORD");
            storageManager.storeAuthToken("server_provided_jwt_token");
            storageManager.storeUserId(username);
            navigateToBalance();
        } else {
            failedAttempts++;
            auditLogger.logLoginAttempt(false, "PASSWORD");
            int remaining = MAX_FAILED_ATTEMPTS - failedAttempts;
            showError("Invalid credentials. " + remaining +
                    " attempts remaining.");
            // Clear password field
            editPassword.setText("");
        }
    }

    private void navigateToBalance() {
        Intent intent = new Intent(this, BalanceActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK |
                Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    private void showError(String message) {
        tvError.setText(message);
        tvError.setVisibility(View.VISIBLE);
    }

    private void showLoading(boolean show) {
        progressBar.setVisibility(show ? View.VISIBLE : View.GONE);
        btnLogin.setEnabled(!show);
        btnBiometric.setEnabled(!show);
    }

    @Override
    protected void onPause() {
        super.onPause();
        // Clear sensitive fields when app goes to background
        editPassword.setText("");
    }

    // Placeholder for BuildConfig reference
    private static class BuildConfig {
        static final boolean DEBUG = true;
    }
}

