package com.securebank.app.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout;

import com.securebank.app.R;
import com.securebank.app.model.Account;
import com.securebank.app.network.TransactionApiService;
import com.securebank.app.security.SecureStorageManager;

import java.util.ArrayList;
import java.util.List;

public class BalanceActivity extends AppCompatActivity {

    private TextView tvTotalBalance;
    private TextView tvWelcome;
    private RecyclerView recyclerAccounts;
    private ProgressBar progressBar;
    private SwipeRefreshLayout swipeRefresh;
    private Button btnTransfer;
    private Button btnLogout;
    private TextView tvError;

    private TransactionApiService apiService;
    private SecureStorageManager storageManager;
    private AccountAdapter accountAdapter;
    private List<Account> accounts = new ArrayList<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        getWindow().setFlags(
                WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE);

        setContentView(R.layout.activity_balance);

        storageManager = SecureStorageManager.getInstance(this);
        apiService = new TransactionApiService(this);

        if (!storageManager.isSessionValid()) {
            redirectToLogin();
            return;
        }

        initViews();
        setupListeners();
        loadAccounts();
    }

    private void initViews() {
        tvTotalBalance = findViewById(R.id.tv_total_balance);
        tvWelcome = findViewById(R.id.tv_welcome);
        recyclerAccounts = findViewById(R.id.recycler_accounts);
        progressBar = findViewById(R.id.progress_bar);
        swipeRefresh = findViewById(R.id.swipe_refresh);
        btnTransfer = findViewById(R.id.btn_transfer);
        btnLogout = findViewById(R.id.btn_logout);
        tvError = findViewById(R.id.tv_error);

        recyclerAccounts.setLayoutManager(new LinearLayoutManager(this));
        accountAdapter = new AccountAdapter(accounts, account -> {
            Intent intent = new Intent(this, TransactionActivity.class);
            intent.putExtra("account_id", account.getAccountId());
            intent.putExtra("account_name", account.getAccountName());
            intent.putExtra("balance",
                    account.getBalance().toPlainString());
            intent.putExtra("currency", account.getCurrency());
            startActivity(intent);
        });
        recyclerAccounts.setAdapter(accountAdapter);

        String userId = storageManager.getUserId();
        if (userId != null) {
            tvWelcome.setText(String.format("Welcome, %s",
                    maskUserDisplay(userId)));
        }
    }

    private void setupListeners() {
        swipeRefresh.setOnRefreshListener(this::loadAccounts);

        btnTransfer.setOnClickListener(v -> {
            if (accounts.isEmpty()) {
                Toast.makeText(this, "No accounts available",
                        Toast.LENGTH_SHORT).show();
                return;
            }
            Intent intent = new Intent(this, TransactionActivity.class);
            intent.putExtra("account_id",
                    accounts.get(0).getAccountId());
            intent.putExtra("account_name",
                    accounts.get(0).getAccountName());
            intent.putExtra("balance",
                    accounts.get(0).getBalance().toPlainString());
            intent.putExtra("currency",
                    accounts.get(0).getCurrency());
            startActivity(intent);
        });

        btnLogout.setOnClickListener(v -> {
            storageManager.clearSession();
            redirectToLogin();
        });
    }

    private void loadAccounts() {
        showLoading(true);
        tvError.setVisibility(View.GONE);

        storageManager.refreshSession();

        apiService.fetchAccounts()
                .thenAccept(fetchedAccounts -> runOnUiThread(() -> {
                    showLoading(false);
                    accounts.clear();
                    accounts.addAll(fetchedAccounts);
                    accountAdapter.notifyDataSetChanged();
                    updateTotalBalance();
                }))
                .exceptionally(throwable -> {
                    runOnUiThread(() -> {
                        showLoading(false);
                        tvError.setText("Failed to load accounts. " +
                                "Pull to refresh.");
                        tvError.setVisibility(View.VISIBLE);
                    });
                    return null;
                });
    }

    private void updateTotalBalance() {
        java.math.BigDecimal total = java.math.BigDecimal.ZERO;
        String currency = "USD";
        for (Account account : accounts) {
            if (account.getBalance() != null) {
                total = total.add(account.getBalance());
            }
            if (account.getCurrency() != null) {
                currency = account.getCurrency();
            }
        }
        tvTotalBalance.setText(String.format("%s %,.2f", currency, total));
    }

    private void showLoading(boolean show) {
        if (show) {
            progressBar.setVisibility(View.VISIBLE);
        } else {
            progressBar.setVisibility(View.GONE);
            swipeRefresh.setRefreshing(false);
        }
    }

    private String maskUserDisplay(String userId) {
        if (userId.length() <= 3) return userId;
        return userId.substring(0, 3) + "***";
    }

    private void redirectToLogin() {
        Intent intent = new Intent(this, LoginActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK |
                Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (!storageManager.isSessionValid()) {
            redirectToLogin();
            return;
        }
        storageManager.refreshSession();
        loadAccounts();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (apiService != null) {
            apiService.shutdown();
        }
    }
}

