package com.securebank.app.ui;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.securebank.app.R;
import com.securebank.app.model.Account;

import java.util.List;

public class AccountAdapter extends
        RecyclerView.Adapter<AccountAdapter.AccountViewHolder> {

    public interface OnAccountClickListener {
        void onAccountClick(Account account);
    }

    private final List<Account> accounts;
    private final OnAccountClickListener listener;

    public AccountAdapter(List<Account> accounts,
                          OnAccountClickListener listener) {
        this.accounts = accounts;
        this.listener = listener;
    }

    @NonNull
    @Override
    public AccountViewHolder onCreateViewHolder(@NonNull ViewGroup parent,
                                                 int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_account, parent, false);
        return new AccountViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull AccountViewHolder holder,
                                  int position) {
        Account account = accounts.get(position);
        holder.bind(account, listener);
    }

    @Override
    public int getItemCount() {
        return accounts.size();
    }

    static class AccountViewHolder extends RecyclerView.ViewHolder {
        private final TextView tvAccountName;
        private final TextView tvAccountType;
        private final TextView tvAccountNumber;
        private final TextView tvBalance;

        AccountViewHolder(@NonNull View itemView) {
            super(itemView);
            tvAccountName = itemView.findViewById(R.id.tv_account_name);
            tvAccountType = itemView.findViewById(R.id.tv_account_type);
            tvAccountNumber = itemView.findViewById(R.id.tv_account_number);
            tvBalance = itemView.findViewById(R.id.tv_balance);
        }

        void bind(Account account, OnAccountClickListener listener) {
            tvAccountName.setText(account.getAccountName());
            tvAccountType.setText(account.getAccountType());
            tvAccountNumber.setText(account.getMaskedAccountNumber());
            tvBalance.setText(account.getFormattedBalance());

            itemView.setOnClickListener(v -> {
                if (listener != null) {
                    listener.onAccountClick(account);
                }
            });
        }
    }
}

