    private void extractIntentData() {
        accountId = getIntent().getStringExtra("account_id");
        accountName = getIntent().getStringExtra("account_name");
        balance = getIntent().getStringExtra("balance");
        currency = getIntent().getStringExtra("currency");

        if (accountId == null) {
            finish();
        }
    }

    private void initViews() {
        tvFromAccount = findViewById(R.id.tv_from_account);
        tvAvailableBalance = findViewById(R.id.tv_available_balance);
        tilAccountNumber = findViewById(R.id.til_account_number);
        tilBeneficiaryName = findViewById(R.id.til_beneficiary_name);
        tilAmount = findViewById(R.id.til_amount);
        tilDescription = findViewById(R.id.til_description);
        editAccountNumber = findViewById(R.id.edit_account_number);
        editBeneficiaryName = findViewById(R.id.edit_beneficiary_name);
        editAmount = findViewById(R.id.edit_amount);
        editDescription = findViewById(R.id.edit_description);
        btnSubmit = findViewById(R.id.btn_submit);
        btnCancel = findViewById(R.id.btn_cancel);
        progressBar = findViewById(R.id.progress_bar);
        tvStatus = findViewById(R.id.tv_status);

        tvFromAccount.setText(String.format("From: %s", accountName));
        if (balance != null && currency != null) {
            tvAvailableBalance.setText(String.format("Available: %s %s",
                    currency, balance));
        }
    }

    private void setupListeners() {
        // Clear errors on text change
        editAccountNumber.addTextChangedListener(
                createClearErrorWatcher(tilAccountNumber));
        editBeneficiaryName.addTextChangedListener(
                createClearErrorWatcher(tilBeneficiaryName));
        editAmount.addTextChangedListener(
                createClearErrorWatcher(tilAmount));
        editDescription.addTextChangedListener(
                createClearErrorWatcher(tilDescription));

        btnSubmit.setOnClickListener(v -> {
            if (isProcessing) return;
            showConfirmationDialog();
        });

        btnCancel.setOnClickListener(v -> {
            if (!isProcessing) {
                finish();
            }
        });
    }

    private void showConfirmationDialog() {
        String amount = editAmount.getText().toString().trim();
        String beneficiary = editBeneficiaryName.getText().toString().trim();
        String toAccount = editAccountNumber.getText().toString().trim();

        if (amount.isEmpty() || beneficiary.isEmpty() || toAccount.isEmpty()) {
            // Let validation handle specific errors
            submitTransaction();
            return;
        }

        new AlertDialog.Builder(this)
                .setTitle("Confirm Transfer")
                .setMessage(String.format(
                        "Transfer %s %s to %s (Account: %s)?\n\n" +
                                "This action cannot be undone.",
                        currency, amount, beneficiary, maskAccountNumber(toAccount)))
                .setPositiveButton("Confirm", (dialog, which) -> {
                    authenticateAndSubmit();
                })
                .setNegativeButton("Cancel", null)
                .setCancelable(true)
                .show();
    }

